import React, { useState, useRef, useEffect } from 'react';
import { Plane, Calendar, Clock, User, TrendingUp } from 'lucide-react';

const VacationForm = ({ onAddVacation, leaveBalances }) => {
  const [name, setName] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [leaveType, setLeaveType] = useState('EL');

  // Refs for auto-focusing
  const endDateRef = useRef(null);

  // Auto-focus end date when start date is selected
  useEffect(() => {
    if (startDate && endDateRef.current) {
      // Small delay to ensure the input is ready
      setTimeout(() => {
        endDateRef.current.focus();
      }, 100);
    }
  }, [startDate]);

  const calculateDuration = (start, end) => {
    if (!start || !end) return 0;
    const startDate = new Date(start);
    const endDate = new Date(end);
    const diffTime = Math.abs(endDate - startDate);
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
    return diffDays + 1; // Include both start and end dates
  };

  const handleStartDateChange = (e) => {
    const newStartDate = e.target.value;
    setStartDate(newStartDate);

    // Clear end date if it's now before the new start date
    if (endDate && new Date(endDate) < new Date(newStartDate)) {
      setEndDate('');
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    if (!name.trim() || !startDate || !endDate) {
      alert('Please fill in all required fields');
      return;
    }

    if (new Date(startDate) > new Date(endDate)) {
      alert('End date must be after start date');
      return;
    }

    const duration = calculateDuration(startDate, endDate);

    // Check if user has enough leave balance
    const currentBalance = leaveBalances?.[leaveType] || 0;
    if (duration > currentBalance) {
      alert(`Insufficient ${leaveType} balance. You have ${currentBalance} days but requesting ${duration} days.`);
      return;
    }

    onAddVacation({
      name: name.trim(),
      fromDate: startDate,
      toDate: endDate,
      days: duration,
      leaveType: leaveType
    });

    // Reset form
    setName('');
    setStartDate('');
    setEndDate('');
    setLeaveType('EL');
  };

  const duration = calculateDuration(startDate, endDate);
  const currentBalance = leaveBalances?.[leaveType] || 0;
  const remainingBalance = currentBalance - duration;

  // Get today's date in YYYY-MM-DD format for min attribute
  const today = new Date().toISOString().split('T')[0];

  // Get start date for end date min attribute
  const minEndDate = startDate || today;

  return (
    <div className="bg-white rounded-lg shadow p-6">
      <h3 className="text-lg font-semibold text-gray-900 mb-4 flex items-center">
        <Plane className="w-5 h-5 mr-2 text-green-600" />
        Request Vacation
      </h3>

      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label htmlFor="vacationName" className="block text-sm font-medium text-gray-700 mb-1">
            Vacation Name
          </label>
          <div className="relative">
            <User className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-400" />
            <input
              type="text"
              id="vacationName"
              value={name}
              onChange={(e) => setName(e.target.value)}
              className="w-full pl-10 pr-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-green-500 focus:border-transparent"
              placeholder="e.g., Summer Vacation"
              required
            />
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div>
            <label htmlFor="startDate" className="block text-sm font-medium text-gray-700 mb-1">
              Start Date
            </label>
            <div className="relative">
              <Calendar className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-400" />
              <input
                type="date"
                id="startDate"
                value={startDate}
                onChange={handleStartDateChange}
                min={today}
                className="w-full pl-10 pr-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-green-500 focus:border-transparent"
                required
              />
            </div>
            <p className="mt-1 text-xs text-gray-500">
              Select your vacation start date
            </p>
          </div>

          <div>
            <label htmlFor="endDate" className="block text-sm font-medium text-gray-700 mb-1">
              End Date
            </label>
            <div className="relative">
              <Calendar className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-400" />
              <input
                type="date"
                id="endDate"
                value={endDate}
                onChange={(e) => setEndDate(e.target.value)}
                ref={endDateRef}
                min={minEndDate}
                className="w-full pl-10 pr-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-green-500 focus:border-transparent"
                required
                disabled={!startDate}
              />
            </div>
            <p className="mt-1 text-xs text-gray-500">
              {startDate ? 'Select your vacation end date' : 'Select start date first'}
            </p>
          </div>
        </div>

        {/* Leave Type Selection */}
        <div>
          <label htmlFor="leaveType" className="block text-sm font-medium text-gray-700 mb-1">
            Leave Type
          </label>
          <div className="relative">
            <TrendingUp className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-400" />
            <select
              id="leaveType"
              value={leaveType}
              onChange={(e) => setLeaveType(e.target.value)}
              className="w-full pl-10 pr-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-green-500 focus:border-transparent"
              required
            >
              <option value="EL">Earned Leave (EL) - {leaveBalances?.EL || 0} days available</option>
              <option value="CL">Casual Leave (CL) - {leaveBalances?.CL || 0} days available</option>
              <option value="SL">Sick Leave (SL) - {leaveBalances?.SL || 0} days available</option>
            </select>
          </div>
          {/* Debug info */}
          <div className="mt-1 text-xs text-gray-500">
            Debug: leaveBalances = {JSON.stringify(leaveBalances)}
          </div>
        </div>

        {duration > 0 && (
          <div className="space-y-3">
            <div className="flex items-center p-3 bg-green-50 border border-green-200 rounded-md">
              <Clock className="w-4 h-4 text-green-600 mr-2" />
              <span className="text-sm text-green-800">
                Duration: <strong>{duration} day{duration !== 1 ? 's' : ''}</strong>
              </span>
            </div>

            {/* Leave Balance Check */}
            <div className={`p-3 border rounded-md ${
              remainingBalance >= 0 ? 'bg-blue-50 border-blue-200' : 'bg-red-50 border-red-200'
            }`}>
              <div className="flex items-center justify-between text-sm">
                <span className={remainingBalance >= 0 ? 'text-blue-800' : 'text-red-800'}>
                  {leaveType} Balance Check:
                </span>
                <span className={`font-semibold ${remainingBalance >= 0 ? 'text-blue-900' : 'text-red-900'}`}>
                  {currentBalance} - {duration} = {remainingBalance} days remaining
                </span>
              </div>
              {remainingBalance < 0 && (
                <p className="text-xs text-red-600 mt-1">
                  ⚠️ Insufficient leave balance. Please reduce duration or select different leave type.
                </p>
              )}
            </div>
          </div>
        )}

        <button
          type="submit"
          disabled={duration > currentBalance}
          className={`w-full flex items-center justify-center px-4 py-2 rounded-md focus:outline-none focus:ring-2 focus:ring-green-500 focus:ring-offset-2 ${
            duration > currentBalance
              ? 'bg-gray-400 text-gray-600 cursor-not-allowed'
              : 'bg-green-600 text-white hover:bg-green-700'
          }`}
        >
          <Plane className="w-4 h-4 mr-2" />
          Submit Vacation Request
        </button>
      </form>
    </div>
  );
};

export default VacationForm;
